mapper.select:
WITH RECURSIVE ordered_slot AS ( SELECT s.id, s.user_id, o.faction_id, s.oc_id, s.join_time, ROW_NUMBER() OVER (PARTITION BY s.oc_id ORDER BY s.join_time ASC, s.id ASC) AS slot_order FROM torn_faction_oc_slot s INNER JOIN torn_faction_oc o ON o.id = s.oc_id AND o.status IN ('Successful', 'Failure') WHERE s.deleted = 0 AND o.deleted = 0 AND s.user_id IS NOT NULL AND s.join_time IS NOT NULL AND o.faction_id = #{factionId} ), idle_data AS ( SELECT id, user_id, faction_id, oc_id, join_time, slot_order, join_time AS prepare_start_time FROM ordered_slot WHERE slot_order = 1
UNION ALL
SELECT current_slot.id, current_slot.user_id, current_slot.faction_id, current_slot.oc_id, current_slot.join_time, current_slot.slot_order, GREATEST(current_slot.join_time, previous_slot.prepare_start_time + INTERVAL '24 hours') AS prepare_start_time FROM ordered_slot current_slot INNER JOIN idle_data previous_slot ON previous_slot.oc_id = current_slot.oc_id AND previous_slot.slot_order + 1 = current_slot.slot_order ) SELECT user_id AS userId, faction_id AS factionId, SUM(EXTRACT(EPOCH FROM (prepare_start_time - join_time)))::BIGINT AS idleSeconds, COUNT(DISTINCT oc_id) AS ocCount FROM idle_data WHERE prepare_start_time BETWEEN #{fromDate} AND #{toDate} AND prepare_start_time > join_time GROUP BY user_id, faction_id ORDER BY idleSeconds DESC LIMIT #{limit}
